#include <stdio.h>
int main() {
    int N, Q;
    scanf("%d %d", &N, &Q);
    int A[N], prefixSum[N + 1];
    prefixSum[0] = 0;
    for (int i = 0; i < N; i++) {
        scanf("%d", &A[i]);
        prefixSum[i + 1] = prefixSum[i] + A[i];
    }
    for (int i = 0; i < Q; i++) {
        char query;
        scanf(" %c", &query);
        if (query == 'S') {
            int i, j;
            scanf("%d %d", &i, &j);
            printf("%d\n", prefixSum[j + 1] - prefixSum[i]);
        } else if (query == 'G') {
            int i, num_marbles;
            scanf("%d %d", &i, &num_marbles);
            A[i] += num_marbles;
            prefixSum[i + 1] = prefixSum[i] + A[i];
            for (int j = i + 1; j <= N; j++) {
                prefixSum[j] = prefixSum[j - 1] + A[j - 1];
            }
        } else if (query == 'T') {
            int i, num_marbles;
            scanf("%d %d", &i, &num_marbles);
            A[i] -= num_marbles;
            prefixSum[i + 1] = prefixSum[i] + A[i];
            for (int j = i + 1; j <= N; j++) {
                prefixSum[j] = prefixSum[j - 1] + A[j - 1];
            }
        }
    }
    return 0;
}

