                System.out.println(prefixSum[j + 1] - prefixSum[i1]);
            } else if (query == 'G') {
                int i1 = scanner.nextInt();
                int num_marbles = scanner.nextInt();
                A[i1] += num_marbles;
                prefixSum[i1 + 1] = prefixSum[i1] + A[i1];
                for (int j = i1 + 1; j <= N; j++) {
                    prefixSum[j] = prefixSum[j - 1] + A[j - 1];
                }
            } else if (query == 'T') {
                int i1 = scanner.nextInt();
                int num_marbles = scanner.nextInt();
